// Self-destroying service worker.
//
// 이 파일은 기능용 서비스 워커가 아닙니다. 예전 블로그가 이 도메인에 등록해 둔
// 옛날 sw.min.js 가 방문자 브라우저에 아직 살아있어서 낡은 캐시를 계속 서빙하는
// 문제를 정리하기 위한 것입니다. 브라우저가 다음 업데이트 검사 때 이 새 버전을
// 받으면 install -> activate 가 일어나고, 그 과정에서 모든 캐시를 비우고 자기
// 자신을 unregister 한 뒤 열려 있는 탭을 새로고침해 서비스 워커 없는 현재
// 사이트로 되돌립니다.
//
// 거의 모든 방문자가 이 워커를 거쳐갈 만큼 충분히 배포된 뒤에도, 뒤늦게 돌아오는
// 방문자를 위해 이 파일은 그대로 두는 편이 안전합니다(지우면 옛 워커를 가진
// 브라우저가 다시 404 를 만나 정리되지 않습니다).

self.addEventListener('install', () => {
  self.skipWaiting()
})

self.addEventListener('activate', (event) => {
  event.waitUntil(
    (async () => {
      // 1. 이 등록(registration) 자체를 해제한다.
      await self.registration.unregister()

      // 2. 옛 워커가 남긴 모든 캐시를 삭제한다.
      const keys = await caches.keys()
      await Promise.all(keys.map((key) => caches.delete(key)))

      // 3. 제어 중이던 모든 탭을 새로고침해 워커 없는 현재 사이트를 받게 한다.
      const clients = await self.clients.matchAll({ type: 'window' })
      for (const client of clients) {
        client.navigate(client.url)
      }
    })()
  )
})
